codeComparison.old:
// Old way with a for loop
let fahrenheit = [];
for (let i = 0; i < celsius.length; i++) {
  fahrenheit.push((celsius[i] * 9/5) + 32);
}

codeComparison.new:
// New way with .map()
let fahrenheit = celsius.map(c => (c * 9/5) + 32);

// Even with formatting
let formatted = celsius.map(c => {
  let f = (c * 9/5) + 32;
  return f.toFixed(1);
});
